import logging
import os

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def detect_format_from_content(filepath):
    """Detect format by reading the first line."""
    with open(filepath, 'r') as f:
        first_line = f.readline()
    if '\t' in first_line:
        return 'tsv'
    if ':' in first_line:
        return 'yaml'
    return None

def parse_exchange_table_file(f):
    header = f.readline()
    for line in f:
        parts = line.strip().split('\t')
        if len(parts) != 3:
            logging.getLogger(__name__).warning(f"Skipping malformed line: {line.strip()}")
            continue
        yield {'compound': parts[0], 'lower': float(parts[1]), 'upper': float(parts[2])}

def parse_exchange_yaml_file(context, f, default_compartment):
    for line in f:
        parts = line.strip().split(':')
        if len(parts) < 3:
            logging.getLogger(__name__).warning(f"Skipping malformed line: {line.strip()}")
            continue
        entry = {
            'compound': parts[0],
            'lower': float(parts[1]),
            'upper': float(parts[2]),
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    context = FilePathContext(path)
    format = resolve_format(None, context.filepath)
    if format is None:
        format = detect_format_from_content(context.filepath)
    if format is None:
        raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))
    if format == 'tsv':
        logger.debug('Parsing exchange file {} as TSV'.format(context.filepath))
        with context.open('r') as f:
            for entry in parse_exchange_table_file(f):
                if entry['lower'] > entry['upper']:
                    raise ValueError(f"lower bound greater than upper bound for compound {entry['compound']}")
                yield entry
    elif format == 'yaml':
        logger.debug('Parsing exchange file {} as YAML'.format(context.filepath))
        with context.open('r') as f:
            for entry in parse_exchange_yaml_file(context, f, default_compartment):
                if entry['lower'] > entry['upper']:
                    raise ValueError(f"lower bound greater than upper bound for compound {entry['compound']}")
                yield entry
    else:
        raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))
